window.BIBLE["Ecclesiastes"] = {"1":{"chapter":"1","title":"VANITY OF VANITIES","verses":{"1":{"text":"The words of the Preacher, the son of David, king in Jerusalem.","ref":"Ecclesiastes 1:1","synthesized":"These are the words of the Teacher, the son of David, king in Jerusalem:","sources":{"KJV":{"text":"The words of the Preacher, the son of David, king in Jerusalem."},"BSB":{"text":"These are the words of the Teacher, the son of David, king in Jerusalem:"}},"definableWords":["son","king","Jerusalem"],"peopleInVerse":["David"]},"2":{"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity.","ref":"Ecclesiastes 1:2","synthesized":"“Futility of futilities,” says the Teacher, “futility of futilities! Everything is futile!”","sources":{"KJV":{"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity."},"BSB":{"text":"“Futility of futilities,” says the Teacher, “futility of futilities! Everything is futile!”"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"What profit hath a man of all his labour which he taketh under the sun?","ref":"Ecclesiastes 1:3","synthesized":"What does a man gain from all his labor, at which he toils under the sun?","sources":{"KJV":{"text":"What profit hath a man of all his labour which he taketh under the sun?"},"BSB":{"text":"What does a man gain from all his labor, at which he toils under the sun?"}},"definableWords":["man"],"peopleInVerse":[]},"4":{"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever.","ref":"Ecclesiastes 1:4","synthesized":"Generations come and generations go, but the earth remains forever.","sources":{"KJV":{"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever."},"BSB":{"text":"Generations come and generations go, but the earth remains forever."}},"definableWords":["earth"],"peopleInVerse":[]},"5":{"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose.","ref":"Ecclesiastes 1:5","synthesized":"The sun rises and the sun sets; it hurries back to where it rises.","sources":{"KJV":{"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose."},"BSB":{"text":"The sun rises and the sun sets; it hurries back to where it rises."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits.","ref":"Ecclesiastes 1:6","synthesized":"The wind blows southward, then turns northward; round and round it swirls, ever returning on its course.","sources":{"KJV":{"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits."},"BSB":{"text":"The wind blows southward, then turns northward; round and round it swirls, ever returning on its course."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again.","ref":"Ecclesiastes 1:7","synthesized":"All the rivers flow into the sea, yet the sea is never full; to the place from which the streams come, there again they flow.","sources":{"KJV":{"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again."},"BSB":{"text":"All the rivers flow into the sea, yet the sea is never full; to the place from which the streams come, there again they flow."}},"definableWords":["sea"],"peopleInVerse":[]},"8":{"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing.","ref":"Ecclesiastes 1:8","synthesized":"All things are wearisome, more than one can describe; the eye is not satisfied with seeing, nor the ear content with hearing.","sources":{"KJV":{"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing."},"BSB":{"text":"All things are wearisome, more than one can describe; the eye is not satisfied with seeing, nor the ear content with hearing."}},"definableWords":["one"],"peopleInVerse":[]},"9":{"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun.","ref":"Ecclesiastes 1:9","synthesized":"What has been will be again, and what has been done will be done again; there is nothing new under the sun.","sources":{"KJV":{"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun."},"BSB":{"text":"What has been will be again, and what has been done will be done again; there is nothing new under the sun."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us.","ref":"Ecclesiastes 1:10","synthesized":"Is there a case where one can say, “Look, this is new”? It has already existed in the ages before us.","sources":{"KJV":{"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us."},"BSB":{"text":"Is there a case where one can say, “Look, this is new”? It has already existed in the ages before us."}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after.","ref":"Ecclesiastes 1:11","synthesized":"There is no remembrance of those who came before, and those yet to come will not be remembered by those who follow after.","sources":{"KJV":{"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after."},"BSB":{"text":"There is no remembrance of those who came before, and those yet to come will not be remembered by those who follow after."}},"definableWords":["remembered"],"peopleInVerse":[]},"12":{"text":"I the Preacher was king over Israel in Jerusalem.","ref":"Ecclesiastes 1:12","synthesized":"I, the Teacher, was king over Israel in Jerusalem.","sources":{"KJV":{"text":"I the Preacher was king over Israel in Jerusalem."},"BSB":{"text":"I, the Teacher, was king over Israel in Jerusalem."}},"definableWords":["king","Israel","Jerusalem"],"peopleInVerse":[]},"13":{"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith.","ref":"Ecclesiastes 1:13","synthesized":"And I set my mind to seek and explore by wisdom all that is done under heaven. What a heavy burden God has laid upon the sons of men to occupy them!","sources":{"KJV":{"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith."},"BSB":{"text":"And I set my mind to seek and explore by wisdom all that is done under heaven. What a heavy burden God has laid upon the sons of men to occupy them!"}},"definableWords":["mind","seek","wisdom","heaven","God","sons","men"],"peopleInVerse":[]},"14":{"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit.","ref":"Ecclesiastes 1:14","synthesized":"I have seen all the things that are done under the sun, and have found them all to be futile, a pursuit of the wind.","sources":{"KJV":{"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit."},"BSB":{"text":"I have seen all the things that are done under the sun, and have found them all to be futile, a pursuit of the wind."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered.","ref":"Ecclesiastes 1:15","synthesized":"What is crooked cannot be straightened, and what is lacking cannot be counted.","sources":{"KJV":{"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered."},"BSB":{"text":"What is crooked cannot be straightened, and what is lacking cannot be counted."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge.","ref":"Ecclesiastes 1:16","synthesized":"I said to myself, “Behold, I have grown and increased in wisdom beyond all those before me who were over Jerusalem, and my mind has observed a wealth of wisdom and knowledge.”","sources":{"KJV":{"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge."},"BSB":{"text":"I said to myself, “Behold, I have grown and increased in wisdom beyond all those before me who were over Jerusalem, and my mind has observed a wealth of wisdom and knowledge.”"}},"definableWords":["wisdom","Jerusalem","mind","knowledge"],"peopleInVerse":[]},"17":{"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit.","ref":"Ecclesiastes 1:17","synthesized":"So I set my mind to know wisdom and madness and folly; I learned that this, too, is a pursuit of the wind.","sources":{"KJV":{"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit."},"BSB":{"text":"So I set my mind to know wisdom and madness and folly; I learned that this, too, is a pursuit of the wind."}},"definableWords":["mind","wisdom"],"peopleInVerse":[]},"18":{"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow.","ref":"Ecclesiastes 1:18","synthesized":"For with much wisdom comes much sorrow, and as knowledge grows, grief increases.","sources":{"KJV":{"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow."},"BSB":{"text":"For with much wisdom comes much sorrow, and as knowledge grows, grief increases."}},"definableWords":["wisdom","knowledge"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"I MADE ME GREAT WORKS","verses":{"1":{"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity.","ref":"Ecclesiastes 2:1","synthesized":"I said to myself, “Come now, I will test you with pleasure; enjoy what is good!”  But it proved to be futile.","sources":{"KJV":{"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity."},"BSB":{"text":"I said to myself, “Come now, I will test you with pleasure; enjoy what is good!”  But it proved to be futile."}},"definableWords":["good"],"peopleInVerse":[]},"2":{"text":"I said of laughter, It is mad: and of mirth, What doeth it?","ref":"Ecclesiastes 2:2","synthesized":"I said of laughter, “It is folly,” and of pleasure, “What does it accomplish?”","sources":{"KJV":{"text":"I said of laughter, It is mad: and of mirth, What doeth it?"},"BSB":{"text":"I said of laughter, “It is folly,” and of pleasure, “What does it accomplish?”"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life.","ref":"Ecclesiastes 2:3","synthesized":"I sought to cheer my body with wine and to embrace folly—my mind still guiding me with wisdom—until I could see what was worthwhile for men to do under heaven during the few days of their lives.","sources":{"KJV":{"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life."},"BSB":{"text":"I sought to cheer my body with wine and to embrace folly—my mind still guiding me with wisdom—until I could see what was worthwhile for men to do under heaven during the few days of their lives."}},"definableWords":["mind","wisdom","see","men","heaven","days"],"peopleInVerse":[]},"4":{"text":"I made me great works; I builded me houses; I planted me vineyards:","ref":"Ecclesiastes 2:4","synthesized":"I expanded my pursuits. I built houses and planted vineyards for myself.","sources":{"KJV":{"text":"I made me great works; I builded me houses; I planted me vineyards:"},"BSB":{"text":"I expanded my pursuits. I built houses and planted vineyards for myself."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:","ref":"Ecclesiastes 2:5","synthesized":"I made gardens and parks for myself, where I planted all kinds of fruit trees.","sources":{"KJV":{"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:"},"BSB":{"text":"I made gardens and parks for myself, where I planted all kinds of fruit trees."}},"definableWords":["made","trees"],"peopleInVerse":[]},"6":{"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:","ref":"Ecclesiastes 2:6","synthesized":"I built reservoirs to water my groves of flourishing trees.","sources":{"KJV":{"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:"},"BSB":{"text":"I built reservoirs to water my groves of flourishing trees."}},"definableWords":["water","trees"],"peopleInVerse":[]},"7":{"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:","ref":"Ecclesiastes 2:7","synthesized":"I acquired menservants and maidservants, and servants were born in my house. I also owned more herds and flocks than anyone in Jerusalem before me,","sources":{"KJV":{"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:"},"BSB":{"text":"I acquired menservants and maidservants, and servants were born in my house. I also owned more herds and flocks than anyone in Jerusalem before me,"}},"definableWords":["servants","house","Jerusalem"],"peopleInVerse":[]},"8":{"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts.","ref":"Ecclesiastes 2:8","synthesized":"and I accumulated for myself silver and gold and the treasure of kings and provinces. I gathered to myself male and female singers, and the delights of the sons of men—many concubines.","sources":{"KJV":{"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts."},"BSB":{"text":"and I accumulated for myself silver and gold and the treasure of kings and provinces. I gathered to myself male and female singers, and the delights of the sons of men—many concubines."}},"definableWords":["kings","male","female","sons","men"],"peopleInVerse":[]},"9":{"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me.","ref":"Ecclesiastes 2:9","synthesized":"So I became great and surpassed all in Jerusalem who had preceded me; and my wisdom remained with me.","sources":{"KJV":{"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me."},"BSB":{"text":"So I became great and surpassed all in Jerusalem who had preceded me; and my wisdom remained with me."}},"definableWords":["great","Jerusalem","wisdom"],"peopleInVerse":[]},"10":{"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour.","ref":"Ecclesiastes 2:10","synthesized":"Anything my eyes desired, I did not deny myself. I refused my heart no pleasure. For my heart took delight in all my work, and this was the reward for all my labor.","sources":{"KJV":{"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour."},"BSB":{"text":"Anything my eyes desired, I did not deny myself. I refused my heart no pleasure. For my heart took delight in all my work, and this was the reward for all my labor."}},"definableWords":["heart","work"],"peopleInVerse":[]},"11":{"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun.","ref":"Ecclesiastes 2:11","synthesized":"Yet when I considered all the works that my hands had accomplished and what I had toiled to achieve, I found everything to be futile, a pursuit of the wind; there was nothing to be gained under the sun.","sources":{"KJV":{"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun."},"BSB":{"text":"Yet when I considered all the works that my hands had accomplished and what I had toiled to achieve, I found everything to be futile, a pursuit of the wind; there was nothing to be gained under the sun."}},"definableWords":["works"],"peopleInVerse":[]},"12":{"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done.","ref":"Ecclesiastes 2:12","synthesized":"Then I turned to consider wisdom and madness and folly; for what more can the king’s successor do than what has already been accomplished?","sources":{"KJV":{"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done."},"BSB":{"text":"Then I turned to consider wisdom and madness and folly; for what more can the king’s successor do than what has already been accomplished?"}},"definableWords":["wisdom","king"],"peopleInVerse":[]},"13":{"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness.","ref":"Ecclesiastes 2:13","synthesized":"And I saw that wisdom exceeds folly, just as light exceeds darkness:","sources":{"KJV":{"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness."},"BSB":{"text":"And I saw that wisdom exceeds folly, just as light exceeds darkness:"}},"definableWords":["saw","wisdom","light","darkness"],"peopleInVerse":[]},"14":{"text":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all.","ref":"Ecclesiastes 2:14","synthesized":"The wise man has eyes in his head, but the fool walks in darkness.   Yet I also came to realize that one fate overcomes them both.","sources":{"KJV":{"text":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all."},"BSB":{"text":"The wise man has eyes in his head, but the fool walks in darkness.   Yet I also came to realize that one fate overcomes them both."}},"definableWords":["man","fool","darkness","one"],"peopleInVerse":[]},"15":{"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity.","ref":"Ecclesiastes 2:15","synthesized":"So I said to myself, “The fate of the fool will also befall me. What then have I gained by being wise?”  And I said to myself that this too is futile.","sources":{"KJV":{"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity."},"BSB":{"text":"So I said to myself, “The fate of the fool will also befall me. What then have I gained by being wise?”  And I said to myself that this too is futile."}},"definableWords":["fool"],"peopleInVerse":[]},"16":{"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool.","ref":"Ecclesiastes 2:16","synthesized":"For there is no lasting remembrance of the wise, just as with the fool, seeing that both will be forgotten in the days to come. Alas, the wise man will die just like the fool!","sources":{"KJV":{"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool."},"BSB":{"text":"For there is no lasting remembrance of the wise, just as with the fool, seeing that both will be forgotten in the days to come. Alas, the wise man will die just like the fool!"}},"definableWords":["fool","days","man","die"],"peopleInVerse":[]},"17":{"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit.","ref":"Ecclesiastes 2:17","synthesized":"So I hated life, because the work that is done under the sun was grievous to me. For everything is futile and a pursuit of the wind.","sources":{"KJV":{"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit."},"BSB":{"text":"So I hated life, because the work that is done under the sun was grievous to me. For everything is futile and a pursuit of the wind."}},"definableWords":["life","work"],"peopleInVerse":[]},"18":{"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me.","ref":"Ecclesiastes 2:18","synthesized":"I hated all for which I had toiled under the sun, because I must leave it to the man who comes after me.","sources":{"KJV":{"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me."},"BSB":{"text":"I hated all for which I had toiled under the sun, because I must leave it to the man who comes after me."}},"definableWords":["man"],"peopleInVerse":[]},"19":{"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity.","ref":"Ecclesiastes 2:19","synthesized":"And who knows whether that man will be wise or foolish? Yet he will take over all the labor at which I have worked skillfully under the sun. This too is futile.","sources":{"KJV":{"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity."},"BSB":{"text":"And who knows whether that man will be wise or foolish? Yet he will take over all the labor at which I have worked skillfully under the sun. This too is futile."}},"definableWords":["man","or"],"peopleInVerse":[]},"20":{"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun.","ref":"Ecclesiastes 2:20","synthesized":"So my heart began to despair over all the labor that I had done under the sun.","sources":{"KJV":{"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun."},"BSB":{"text":"So my heart began to despair over all the labor that I had done under the sun."}},"definableWords":["heart"],"peopleInVerse":[]},"21":{"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil.","ref":"Ecclesiastes 2:21","synthesized":"When there is a man who has labored with wisdom, knowledge, and skill, and he must give his portion to a man who has not worked for it, this too is futile and a great evil.","sources":{"KJV":{"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil."},"BSB":{"text":"When there is a man who has labored with wisdom, knowledge, and skill, and he must give his portion to a man who has not worked for it, this too is futile and a great evil."}},"definableWords":["man","wisdom","knowledge","great","evil"],"peopleInVerse":[]},"22":{"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?","ref":"Ecclesiastes 2:22","synthesized":"For what does a man get for all the toil and striving with which he labors under the sun?","sources":{"KJV":{"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?"},"BSB":{"text":"For what does a man get for all the toil and striving with which he labors under the sun?"}},"definableWords":["man"],"peopleInVerse":[]},"23":{"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity.","ref":"Ecclesiastes 2:23","synthesized":"Indeed, all his days are filled with grief, and his task is sorrowful; even at night, his mind does not rest. This too is futile.","sources":{"KJV":{"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity."},"BSB":{"text":"Indeed, all his days are filled with grief, and his task is sorrowful; even at night, his mind does not rest. This too is futile."}},"definableWords":["days","night","mind","rest"],"peopleInVerse":[]},"24":{"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God.","ref":"Ecclesiastes 2:24","synthesized":"Nothing is better for a man than to eat and drink and enjoy his work. I have also seen that this is from the hand of God.","sources":{"KJV":{"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God."},"BSB":{"text":"Nothing is better for a man than to eat and drink and enjoy his work. I have also seen that this is from the hand of God."}},"definableWords":["man","work","God"],"peopleInVerse":[]},"25":{"text":"For who can eat, or who else can hasten hereunto, more than I?","ref":"Ecclesiastes 2:25","synthesized":"For apart from Him, who can eat and who can find enjoyment?","sources":{"KJV":{"text":"For who can eat, or who else can hasten hereunto, more than I?"},"BSB":{"text":"For apart from Him, who can eat and who can find enjoyment?"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit.","ref":"Ecclesiastes 2:26","synthesized":"To the man who is pleasing in His sight, He gives wisdom and knowledge and joy, but to the sinner He assigns the task of gathering and accumulating that which he will hand over to one who pleases God. This too is futile and a pursuit of the wind.","sources":{"KJV":{"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit."},"BSB":{"text":"To the man who is pleasing in His sight, He gives wisdom and knowledge and joy, but to the sinner He assigns the task of gathering and accumulating that which he will hand over to one who pleases God. This too is futile and a pursuit of the wind."}},"definableWords":["man","wisdom","knowledge","joy","one","God"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"A TIME FOR EVERYTHING","verses":{"1":{"text":"To every thing there is a season, and a time to every purpose under the heaven:","ref":"Ecclesiastes 3:1","synthesized":"To everything there is a season, and a time for every purpose under heaven:","sources":{"KJV":{"text":"To every thing there is a season, and a time to every purpose under the heaven:"},"BSB":{"text":"To everything there is a season, and a time for every purpose under heaven:"}},"definableWords":["heaven"],"peopleInVerse":[],"kingdomLens":"'To every thing there is a season... a time to be born, and a time to die; a time to plant, and a time to pluck up' (Eccl 3:1-2). Solomon's most quoted passage. Then verse 11: 'He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.' We sense eternity. We just can't see the whole picture.","cultural":{"title":"A time for every purpose under heaven","detail":"Set to music in 1959 by Pete Seeger and recorded by The Byrds as 'Turn! Turn! Turn!' — became a #1 hit. The song is the Bible verbatim except for the closing line 'a time for peace, I swear it's not too late.' Ecclesiastes 3 became part of American pop culture.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;","ref":"Ecclesiastes 3:2","synthesized":"a time to be born and a time to die, a time to plant and a time to uproot,","sources":{"KJV":{"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;"},"BSB":{"text":"a time to be born and a time to die, a time to plant and a time to uproot,"}},"definableWords":["die"],"peopleInVerse":[]},"3":{"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;","ref":"Ecclesiastes 3:3","synthesized":"a time to kill and a time to heal, a time to break down and a time to build,","sources":{"KJV":{"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;"},"BSB":{"text":"a time to kill and a time to heal, a time to break down and a time to build,"}},"definableWords":["heal"],"peopleInVerse":[]},"4":{"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;","ref":"Ecclesiastes 3:4","synthesized":"a time to weep and a time to laugh, a time to mourn and a time to dance,","sources":{"KJV":{"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;"},"BSB":{"text":"a time to weep and a time to laugh, a time to mourn and a time to dance,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;","ref":"Ecclesiastes 3:5","synthesized":"a time to cast away stones and a time to gather stones together, a time to embrace and a time to refrain from embracing,","sources":{"KJV":{"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;"},"BSB":{"text":"a time to cast away stones and a time to gather stones together, a time to embrace and a time to refrain from embracing,"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;","ref":"Ecclesiastes 3:6","synthesized":"a time to search and a time to count as lost, a time to keep and a time to discard,","sources":{"KJV":{"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;"},"BSB":{"text":"a time to search and a time to count as lost, a time to keep and a time to discard,"}},"definableWords":["keep"],"peopleInVerse":[]},"7":{"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;","ref":"Ecclesiastes 3:7","synthesized":"a time to tear and a time to mend, a time to be silent and a time to speak,","sources":{"KJV":{"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;"},"BSB":{"text":"a time to tear and a time to mend, a time to be silent and a time to speak,"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"A time to love, and a time to hate; a time of war, and a time of peace.","ref":"Ecclesiastes 3:8","synthesized":"a time to love and a time to hate, a time for war and a time for peace.","sources":{"KJV":{"text":"A time to love, and a time to hate; a time of war, and a time of peace."},"BSB":{"text":"a time to love and a time to hate, a time for war and a time for peace."}},"definableWords":["love","peace"],"peopleInVerse":[]},"9":{"text":"What profit hath he that worketh in that wherein he laboureth?","ref":"Ecclesiastes 3:9","synthesized":"What does the worker gain from his toil?","sources":{"KJV":{"text":"What profit hath he that worketh in that wherein he laboureth?"},"BSB":{"text":"What does the worker gain from his toil?"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it.","ref":"Ecclesiastes 3:10","synthesized":"I have seen the burden that God has laid upon the sons of men to occupy them.","sources":{"KJV":{"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it."},"BSB":{"text":"I have seen the burden that God has laid upon the sons of men to occupy them."}},"definableWords":["God","sons","men"],"peopleInVerse":[]},"11":{"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.","ref":"Ecclesiastes 3:11","synthesized":"He has made everything beautiful in its time. He has also set eternity in the hearts of men, yet they cannot fathom the work that God has done from beginning to end.","sources":{"KJV":{"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end."},"BSB":{"text":"He has made everything beautiful in its time. He has also set eternity in the hearts of men, yet they cannot fathom the work that God has done from beginning to end."}},"definableWords":["made","men","work","God","beginning"],"peopleInVerse":[]},"12":{"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life.","ref":"Ecclesiastes 3:12","synthesized":"I know that there is nothing better for them than to rejoice and do good while they live,","sources":{"KJV":{"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life."},"BSB":{"text":"I know that there is nothing better for them than to rejoice and do good while they live,"}},"definableWords":["good","live"],"peopleInVerse":[]},"13":{"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God.","ref":"Ecclesiastes 3:13","synthesized":"and also that every man should eat and drink and find satisfaction in all his labor—this is the gift of God.","sources":{"KJV":{"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God."},"BSB":{"text":"and also that every man should eat and drink and find satisfaction in all his labor—this is the gift of God."}},"definableWords":["man","God"],"peopleInVerse":[]},"14":{"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him.","ref":"Ecclesiastes 3:14","synthesized":"I know that everything God does endures forever; nothing can be added to it or taken from it. God does it so that they should fear Him.","sources":{"KJV":{"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him."},"BSB":{"text":"I know that everything God does endures forever; nothing can be added to it or taken from it. God does it so that they should fear Him."}},"definableWords":["God","or","fear"],"peopleInVerse":[]},"15":{"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past.","ref":"Ecclesiastes 3:15","synthesized":"What exists has already been, and what will be has already been, for God will call to account what has passed.","sources":{"KJV":{"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past."},"BSB":{"text":"What exists has already been, and what will be has already been, for God will call to account what has passed."}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there.","ref":"Ecclesiastes 3:16","synthesized":"Furthermore, I saw under the sun that in the place of judgment there is wickedness, and in the place of righteousness there is wickedness.","sources":{"KJV":{"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there."},"BSB":{"text":"Furthermore, I saw under the sun that in the place of judgment there is wickedness, and in the place of righteousness there is wickedness."}},"definableWords":["saw","judgment","righteousness"],"peopleInVerse":[]},"17":{"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work.","ref":"Ecclesiastes 3:17","synthesized":"I said in my heart, “God will judge the righteous and the wicked, since there is a time for every activity and every deed.”","sources":{"KJV":{"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work."},"BSB":{"text":"I said in my heart, “God will judge the righteous and the wicked, since there is a time for every activity and every deed.”"}},"definableWords":["heart","God","righteous"],"peopleInVerse":[]},"18":{"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts.","ref":"Ecclesiastes 3:18","synthesized":"I said to myself, “As for the sons of men, God tests them so that they may see for themselves that they are but beasts.”","sources":{"KJV":{"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts."},"BSB":{"text":"I said to myself, “As for the sons of men, God tests them so that they may see for themselves that they are but beasts.”"}},"definableWords":["sons","men","God","see"],"peopleInVerse":[]},"19":{"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity.","ref":"Ecclesiastes 3:19","synthesized":"For the fates of both men and beasts are the same: As one dies, so dies the other—they all have the same breath. Man has no advantage over the animals, since everything is futile.","sources":{"KJV":{"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity."},"BSB":{"text":"For the fates of both men and beasts are the same: As one dies, so dies the other—they all have the same breath. Man has no advantage over the animals, since everything is futile."}},"definableWords":["men","one","breath","man"],"peopleInVerse":[]},"20":{"text":"All go unto one place; all are of the dust, and all turn to dust again.","ref":"Ecclesiastes 3:20","synthesized":"All go to one place; all come from dust, and all return to dust.","sources":{"KJV":{"text":"All go unto one place; all are of the dust, and all turn to dust again."},"BSB":{"text":"All go to one place; all come from dust, and all return to dust."}},"definableWords":["one"],"peopleInVerse":[]},"21":{"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?","ref":"Ecclesiastes 3:21","synthesized":"Who knows if the spirit of man rises upward and the spirit of the animal descends into the earth?","sources":{"KJV":{"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?"},"BSB":{"text":"Who knows if the spirit of man rises upward and the spirit of the animal descends into the earth?"}},"definableWords":["spirit","man","earth"],"peopleInVerse":[]},"22":{"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?","ref":"Ecclesiastes 3:22","synthesized":"I have seen that there is nothing better for a man than to enjoy his work, because that is his lot. For who can bring him to see what will come after him?","sources":{"KJV":{"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?"},"BSB":{"text":"I have seen that there is nothing better for a man than to enjoy his work, because that is his lot. For who can bring him to see what will come after him?"}},"definableWords":["man","work","Lot","see"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"TWO ARE BETTER THAN ONE","verses":{"1":{"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.","ref":"Ecclesiastes 4:1","synthesized":"Again I looked, and I considered all the oppression taking place under the sun. I saw the tears of the oppressed, and they had no comforter; the power lay in the hands of their oppressors, and there was no comforter.","sources":{"KJV":{"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter."},"BSB":{"text":"Again I looked, and I considered all the oppression taking place under the sun. I saw the tears of the oppressed, and they had no comforter; the power lay in the hands of their oppressors, and there was no comforter."}},"definableWords":["saw"],"peopleInVerse":[]},"2":{"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive.","ref":"Ecclesiastes 4:2","synthesized":"So I admired the dead, who had already died, above the living, who are still alive.","sources":{"KJV":{"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive."},"BSB":{"text":"So I admired the dead, who had already died, above the living, who are still alive."}},"definableWords":["living"],"peopleInVerse":[]},"3":{"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun.","ref":"Ecclesiastes 4:3","synthesized":"But better than both is he who has not yet existed, who has not seen the evil that is done under the sun.","sources":{"KJV":{"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun."},"BSB":{"text":"But better than both is he who has not yet existed, who has not seen the evil that is done under the sun."}},"definableWords":["evil"],"peopleInVerse":[]},"4":{"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit.","ref":"Ecclesiastes 4:4","synthesized":"I saw that all labor and success spring from a man’s envy of his neighbor. This too is futile and a pursuit of the wind.","sources":{"KJV":{"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit."},"BSB":{"text":"I saw that all labor and success spring from a man’s envy of his neighbor. This too is futile and a pursuit of the wind."}},"definableWords":["saw","man"],"peopleInVerse":[]},"5":{"text":"The fool foldeth his hands together, and eateth his own flesh.","ref":"Ecclesiastes 4:5","synthesized":"The fool folds his hands and consumes his own flesh.","sources":{"KJV":{"text":"The fool foldeth his hands together, and eateth his own flesh."},"BSB":{"text":"The fool folds his hands and consumes his own flesh."}},"definableWords":["fool","flesh"],"peopleInVerse":[]},"6":{"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit.","ref":"Ecclesiastes 4:6","synthesized":"Better one handful with tranquility than two handfuls with toil and pursuit of the wind.","sources":{"KJV":{"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit."},"BSB":{"text":"Better one handful with tranquility than two handfuls with toil and pursuit of the wind."}},"definableWords":["one"],"peopleInVerse":[]},"7":{"text":"Then I returned, and I saw vanity under the sun.","ref":"Ecclesiastes 4:7","synthesized":"Again, I saw futility under the sun.","sources":{"KJV":{"text":"Then I returned, and I saw vanity under the sun."},"BSB":{"text":"Again, I saw futility under the sun."}},"definableWords":["saw"],"peopleInVerse":[]},"8":{"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail.","ref":"Ecclesiastes 4:8","synthesized":"There is a man all alone, without even a son or brother. And though there is no end to his labor, his eyes are still not content with his wealth: “For whom do I toil and bereave my soul of enjoyment?” This too is futile—a miserable task.","sources":{"KJV":{"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail."},"BSB":{"text":"There is a man all alone, without even a son or brother. And though there is no end to his labor, his eyes are still not content with his wealth: “For whom do I toil and bereave my soul of enjoyment?” This too is futile—a miserable task."}},"definableWords":["man","son","or","brother","soul"],"peopleInVerse":[]},"9":{"text":"Two are better than one; because they have a good reward for their labour.","ref":"Ecclesiastes 4:9","synthesized":"Two are better than one, because they have a good return for their labor.","sources":{"KJV":{"text":"Two are better than one; because they have a good reward for their labour."},"BSB":{"text":"Two are better than one, because they have a good return for their labor."}},"definableWords":["one","good"],"peopleInVerse":[]},"10":{"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up.","ref":"Ecclesiastes 4:10","synthesized":"For if one falls down, his companion can lift him up; but pity the one who falls without another to help him up!","sources":{"KJV":{"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up."},"BSB":{"text":"For if one falls down, his companion can lift him up; but pity the one who falls without another to help him up!"}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"Again, if two lie together, then they have heat: but how can one be warm alone?","ref":"Ecclesiastes 4:11","synthesized":"Again, if two lie down together, they will keep warm; but how can one keep warm alone?","sources":{"KJV":{"text":"Again, if two lie together, then they have heat: but how can one be warm alone?"},"BSB":{"text":"Again, if two lie down together, they will keep warm; but how can one keep warm alone?"}},"definableWords":["keep","one"],"peopleInVerse":[]},"12":{"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken.","ref":"Ecclesiastes 4:12","synthesized":"And though one may be overpowered, two can resist. Moreover, a cord of three strands is not quickly broken.","sources":{"KJV":{"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken."},"BSB":{"text":"And though one may be overpowered, two can resist. Moreover, a cord of three strands is not quickly broken."}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished.","ref":"Ecclesiastes 4:13","synthesized":"Better is a poor but wise youth than an old but foolish king who no longer knows how to take a warning.","sources":{"KJV":{"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished."},"BSB":{"text":"Better is a poor but wise youth than an old but foolish king who no longer knows how to take a warning."}},"definableWords":["king"],"peopleInVerse":[]},"14":{"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor.","ref":"Ecclesiastes 4:14","synthesized":"For the youth has come from the prison to the kingship, though he was born poor in his own kingdom.","sources":{"KJV":{"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor."},"BSB":{"text":"For the youth has come from the prison to the kingship, though he was born poor in his own kingdom."}},"definableWords":["kingdom"],"peopleInVerse":[]},"15":{"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead.","ref":"Ecclesiastes 4:15","synthesized":"I saw that all who lived and walked under the sun followed this second one, the youth who succeeded the king.","sources":{"KJV":{"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead."},"BSB":{"text":"I saw that all who lived and walked under the sun followed this second one, the youth who succeeded the king."}},"definableWords":["saw","walked","one","king"],"peopleInVerse":[]},"16":{"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit.","ref":"Ecclesiastes 4:16","synthesized":"There is no limit to all the people who were before them. Yet the successor will not be celebrated by those who come even later. This too is futile and a pursuit of the wind.","sources":{"KJV":{"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit."},"BSB":{"text":"There is no limit to all the people who were before them. Yet the successor will not be celebrated by those who come even later. This too is futile and a pursuit of the wind."}},"definableWords":["people"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"BE NOT RASH WITH THY MOUTH","verses":{"1":{"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil.","ref":"Ecclesiastes 5:1","synthesized":"Guard your steps when you go to the house of God. Draw near to listen rather than to offer the sacrifice of fools, who do not know that they do wrong.","sources":{"KJV":{"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil."},"BSB":{"text":"Guard your steps when you go to the house of God. Draw near to listen rather than to offer the sacrifice of fools, who do not know that they do wrong."}},"definableWords":["house","God","sacrifice"],"peopleInVerse":[]},"2":{"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few.","ref":"Ecclesiastes 5:2","synthesized":"Do not be quick to speak, and do not be hasty in your heart to utter a word before God. After all, God is in heaven and you are on earth. So let your words be few.","sources":{"KJV":{"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few."},"BSB":{"text":"Do not be quick to speak, and do not be hasty in your heart to utter a word before God. After all, God is in heaven and you are on earth. So let your words be few."}},"definableWords":["heart","word","God","heaven","earth"],"peopleInVerse":[]},"3":{"text":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words.","ref":"Ecclesiastes 5:3","synthesized":"As a dream comes through many cares, so the speech of a fool comes with many words.","sources":{"KJV":{"text":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words."},"BSB":{"text":"As a dream comes through many cares, so the speech of a fool comes with many words."}},"definableWords":["fool"],"peopleInVerse":[]},"4":{"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed.","ref":"Ecclesiastes 5:4","synthesized":"When you make a vow to God, do not delay in fulfilling it, because He takes no pleasure in fools. Fulfill your vow.","sources":{"KJV":{"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed."},"BSB":{"text":"When you make a vow to God, do not delay in fulfilling it, because He takes no pleasure in fools. Fulfill your vow."}},"definableWords":["make","God"],"peopleInVerse":[]},"5":{"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay.","ref":"Ecclesiastes 5:5","synthesized":"It is better not to vow than to make a vow and not fulfill it.","sources":{"KJV":{"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay."},"BSB":{"text":"It is better not to vow than to make a vow and not fulfill it."}},"definableWords":["make"],"peopleInVerse":[]},"6":{"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?","ref":"Ecclesiastes 5:6","synthesized":"Do not let your mouth cause your flesh to sin, and do not tell the messenger that your vow was a mistake. Why should God be angry with your words and destroy the work of your hands?","sources":{"KJV":{"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?"},"BSB":{"text":"Do not let your mouth cause your flesh to sin, and do not tell the messenger that your vow was a mistake. Why should God be angry with your words and destroy the work of your hands?"}},"definableWords":["flesh","sin","God","work"],"peopleInVerse":[]},"7":{"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God.","ref":"Ecclesiastes 5:7","synthesized":"For as many dreams bring futility, so do many words. Therefore, fear God.","sources":{"KJV":{"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God."},"BSB":{"text":"For as many dreams bring futility, so do many words. Therefore, fear God."}},"definableWords":["fear","God"],"peopleInVerse":[]},"8":{"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they.","ref":"Ecclesiastes 5:8","synthesized":"If you see the oppression of the poor and the denial of justice and righteousness in the province, do not be astonished at the matter; for one official is watched by a superior, and others higher still are over them.","sources":{"KJV":{"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they."},"BSB":{"text":"If you see the oppression of the poor and the denial of justice and righteousness in the province, do not be astonished at the matter; for one official is watched by a superior, and others higher still are over them."}},"definableWords":["see","justice","righteousness","one"],"peopleInVerse":[]},"9":{"text":"Moreover the profit of the earth is for all: the king himself is served by the field.","ref":"Ecclesiastes 5:9","synthesized":"The produce of the earth is taken by all; the king himself profits from the fields.","sources":{"KJV":{"text":"Moreover the profit of the earth is for all: the king himself is served by the field."},"BSB":{"text":"The produce of the earth is taken by all; the king himself profits from the fields."}},"definableWords":["earth","king"],"peopleInVerse":[]},"10":{"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity.","ref":"Ecclesiastes 5:10","synthesized":"He who loves money is never satisfied by money, and he who loves wealth is never satisfied by income. This too is futile.","sources":{"KJV":{"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity."},"BSB":{"text":"He who loves money is never satisfied by money, and he who loves wealth is never satisfied by income. This too is futile."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?","ref":"Ecclesiastes 5:11","synthesized":"When good things increase, so do those who consume them; what then is the profit to the owner, except to behold them with his eyes?","sources":{"KJV":{"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?"},"BSB":{"text":"When good things increase, so do those who consume them; what then is the profit to the owner, except to behold them with his eyes?"}},"definableWords":["good"],"peopleInVerse":[]},"12":{"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep.","ref":"Ecclesiastes 5:12","synthesized":"The sleep of the worker is sweet, whether he eats little or much, but the abundance of the rich man permits him no sleep.","sources":{"KJV":{"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep."},"BSB":{"text":"The sleep of the worker is sweet, whether he eats little or much, but the abundance of the rich man permits him no sleep."}},"definableWords":["or","man"],"peopleInVerse":[]},"13":{"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt.","ref":"Ecclesiastes 5:13","synthesized":"There is a grievous evil I have seen under the sun: wealth hoarded to the harm of its owner,","sources":{"KJV":{"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt."},"BSB":{"text":"There is a grievous evil I have seen under the sun: wealth hoarded to the harm of its owner,"}},"definableWords":["evil"],"peopleInVerse":[]},"14":{"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand.","ref":"Ecclesiastes 5:14","synthesized":"or wealth lost in a failed venture, so when that man has a son there is nothing to pass on.","sources":{"KJV":{"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand."},"BSB":{"text":"or wealth lost in a failed venture, so when that man has a son there is nothing to pass on."}},"definableWords":["or","man","son"],"peopleInVerse":[]},"15":{"text":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand.","ref":"Ecclesiastes 5:15","synthesized":"As a man came from his mother’s womb, so he will depart again, naked as he arrived. He takes nothing for his labor to carry in his hands.","sources":{"KJV":{"text":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand."},"BSB":{"text":"As a man came from his mother’s womb, so he will depart again, naked as he arrived. He takes nothing for his labor to carry in his hands."}},"definableWords":["man","mother","naked"],"peopleInVerse":[]},"16":{"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?","ref":"Ecclesiastes 5:16","synthesized":"This too is a grievous evil: Exactly as a man is born, so he will depart. What does he gain as he toils for the wind?","sources":{"KJV":{"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?"},"BSB":{"text":"This too is a grievous evil: Exactly as a man is born, so he will depart. What does he gain as he toils for the wind?"}},"definableWords":["evil","man"],"peopleInVerse":[]},"17":{"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness.","ref":"Ecclesiastes 5:17","synthesized":"Moreover, all his days he eats in darkness, with much sorrow, sickness, and anger.","sources":{"KJV":{"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness."},"BSB":{"text":"Moreover, all his days he eats in darkness, with much sorrow, sickness, and anger."}},"definableWords":["days","darkness","anger"],"peopleInVerse":[]},"18":{"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion.","ref":"Ecclesiastes 5:18","synthesized":"Here is what I have seen to be good and fitting: to eat and drink, and to find satisfaction in all the labor one does under the sun during the few days of life that God has given him—for this is his lot.","sources":{"KJV":{"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion."},"BSB":{"text":"Here is what I have seen to be good and fitting: to eat and drink, and to find satisfaction in all the labor one does under the sun during the few days of life that God has given him—for this is his lot."}},"definableWords":["good","one","days","life","God","Lot"],"peopleInVerse":[]},"19":{"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God.","ref":"Ecclesiastes 5:19","synthesized":"Furthermore, God has given riches and wealth to every man, and He has enabled him to enjoy them, to accept his lot, and to rejoice in his labor. This is a gift from God.","sources":{"KJV":{"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God."},"BSB":{"text":"Furthermore, God has given riches and wealth to every man, and He has enabled him to enjoy them, to accept his lot, and to rejoice in his labor. This is a gift from God."}},"definableWords":["God","man","Lot"],"peopleInVerse":[]},"20":{"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart.","ref":"Ecclesiastes 5:20","synthesized":"For a man seldom considers the days of his life, because God keeps him occupied with the joy of his heart.","sources":{"KJV":{"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart."},"BSB":{"text":"For a man seldom considers the days of his life, because God keeps him occupied with the joy of his heart."}},"definableWords":["man","days","life","God","joy","heart"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"RICHES WITHOUT POWER TO ENJOY","verses":{"1":{"text":"There is an evil which I have seen under the sun, and it is common among men:","ref":"Ecclesiastes 6:1","synthesized":"There is another evil I have seen under the sun, and it weighs heavily upon mankind:","sources":{"KJV":{"text":"There is an evil which I have seen under the sun, and it is common among men:"},"BSB":{"text":"There is another evil I have seen under the sun, and it weighs heavily upon mankind:"}},"definableWords":["evil"],"peopleInVerse":[]},"2":{"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease.","ref":"Ecclesiastes 6:2","synthesized":"God gives a man riches, wealth, and honor, so that he lacks nothing his heart desires; but God does not allow him to enjoy them. Instead, a stranger will enjoy them. This is futile and a grievous affliction.","sources":{"KJV":{"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease."},"BSB":{"text":"God gives a man riches, wealth, and honor, so that he lacks nothing his heart desires; but God does not allow him to enjoy them. Instead, a stranger will enjoy them. This is futile and a grievous affliction."}},"definableWords":["God","man","heart","stranger"],"peopleInVerse":[]},"3":{"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he.","ref":"Ecclesiastes 6:3","synthesized":"A man may father a hundred children and live for many years; yet no matter how long he lives, if he is unsatisfied with his prosperity and does not even receive a proper burial, I say that a stillborn child is better off than he.","sources":{"KJV":{"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he."},"BSB":{"text":"A man may father a hundred children and live for many years; yet no matter how long he lives, if he is unsatisfied with his prosperity and does not even receive a proper burial, I say that a stillborn child is better off than he."}},"definableWords":["man","father","live","years"],"peopleInVerse":[]},"4":{"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness.","ref":"Ecclesiastes 6:4","synthesized":"For a stillborn child enters in futility and departs in darkness, and his name is shrouded in obscurity.","sources":{"KJV":{"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness."},"BSB":{"text":"For a stillborn child enters in futility and departs in darkness, and his name is shrouded in obscurity."}},"definableWords":["darkness","name"],"peopleInVerse":[]},"5":{"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other.","ref":"Ecclesiastes 6:5","synthesized":"The child, though neither seeing the sun nor knowing anything, has more rest than that man,","sources":{"KJV":{"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other."},"BSB":{"text":"The child, though neither seeing the sun nor knowing anything, has more rest than that man,"}},"definableWords":["rest","man"],"peopleInVerse":[]},"6":{"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?","ref":"Ecclesiastes 6:6","synthesized":"even if he lives a thousand years twice over but fails to enjoy his prosperity. Do not all go to the same place?","sources":{"KJV":{"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?"},"BSB":{"text":"even if he lives a thousand years twice over but fails to enjoy his prosperity. Do not all go to the same place?"}},"definableWords":["years"],"peopleInVerse":[]},"7":{"text":"All the labour of man is for his mouth, and yet the appetite is not filled.","ref":"Ecclesiastes 6:7","synthesized":"All a man’s labor is for his mouth, yet his appetite is never satisfied.","sources":{"KJV":{"text":"All the labour of man is for his mouth, and yet the appetite is not filled."},"BSB":{"text":"All a man’s labor is for his mouth, yet his appetite is never satisfied."}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?","ref":"Ecclesiastes 6:8","synthesized":"What advantage, then, has the wise man over the fool? What gain comes to the poor man who knows how to conduct himself before others?","sources":{"KJV":{"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?"},"BSB":{"text":"What advantage, then, has the wise man over the fool? What gain comes to the poor man who knows how to conduct himself before others?"}},"definableWords":["man","fool"],"peopleInVerse":[]},"9":{"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit.","ref":"Ecclesiastes 6:9","synthesized":"Better what the eye can see than the wandering of desire. This too is futile and a pursuit of the wind.","sources":{"KJV":{"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit."},"BSB":{"text":"Better what the eye can see than the wandering of desire. This too is futile and a pursuit of the wind."}},"definableWords":["see"],"peopleInVerse":[]},"10":{"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he.","ref":"Ecclesiastes 6:10","synthesized":"Whatever exists was named long ago, and what happens to a man is foreknown; but he cannot contend with one stronger than he.","sources":{"KJV":{"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he."},"BSB":{"text":"Whatever exists was named long ago, and what happens to a man is foreknown; but he cannot contend with one stronger than he."}},"definableWords":["man","one"],"peopleInVerse":[]},"11":{"text":"Seeing there be many things that increase vanity, what is man the better?","ref":"Ecclesiastes 6:11","synthesized":"For the more words, the more futility—and how does that profit anyone?","sources":{"KJV":{"text":"Seeing there be many things that increase vanity, what is man the better?"},"BSB":{"text":"For the more words, the more futility—and how does that profit anyone?"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?","ref":"Ecclesiastes 6:12","synthesized":"For who knows what is good for a man during the few days in which he passes through his fleeting life like a shadow? Who can tell a man what will come after him under the sun?","sources":{"KJV":{"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?"},"BSB":{"text":"For who knows what is good for a man during the few days in which he passes through his fleeting life like a shadow? Who can tell a man what will come after him under the sun?"}},"definableWords":["good","man","days","life"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"BETTER IS THE END THAN THE BEGINNING","verses":{"1":{"text":"A good name is better than precious ointment; and the day of death than the day of one’s birth.","ref":"Ecclesiastes 7:1","synthesized":"A good name is better than fine perfume, and one’s day of death is better than his day of birth.","sources":{"KJV":{"text":"A good name is better than precious ointment; and the day of death than the day of one’s birth."},"BSB":{"text":"A good name is better than fine perfume, and one’s day of death is better than his day of birth."}},"definableWords":["good","name","one","day","death"],"peopleInVerse":[]},"2":{"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart.","ref":"Ecclesiastes 7:2","synthesized":"It is better to enter a house of mourning than a house of feasting, since death is the end of every man, and the living should take this to heart.","sources":{"KJV":{"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart."},"BSB":{"text":"It is better to enter a house of mourning than a house of feasting, since death is the end of every man, and the living should take this to heart."}},"definableWords":["house","death","man","living","heart"],"peopleInVerse":[]},"3":{"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better.","ref":"Ecclesiastes 7:3","synthesized":"Sorrow is better than laughter, for a sad countenance is good for the heart.","sources":{"KJV":{"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better."},"BSB":{"text":"Sorrow is better than laughter, for a sad countenance is good for the heart."}},"definableWords":["good","heart"],"peopleInVerse":[]},"4":{"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.","ref":"Ecclesiastes 7:4","synthesized":"The heart of the wise is in the house of mourning, but the heart of fools is in the house of pleasure.","sources":{"KJV":{"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth."},"BSB":{"text":"The heart of the wise is in the house of mourning, but the heart of fools is in the house of pleasure."}},"definableWords":["heart","house"],"peopleInVerse":[]},"5":{"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools.","ref":"Ecclesiastes 7:5","synthesized":"It is better to heed a wise man’s rebuke than to listen to the song of fools.","sources":{"KJV":{"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools."},"BSB":{"text":"It is better to heed a wise man’s rebuke than to listen to the song of fools."}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity.","ref":"Ecclesiastes 7:6","synthesized":"For like the crackling of thorns under the pot, so is the laughter of the fool. This too is futile.","sources":{"KJV":{"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity."},"BSB":{"text":"For like the crackling of thorns under the pot, so is the laughter of the fool. This too is futile."}},"definableWords":["fool"],"peopleInVerse":[]},"7":{"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart.","ref":"Ecclesiastes 7:7","synthesized":"Surely extortion turns a wise man into a fool, and a bribe corrupts the heart.","sources":{"KJV":{"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart."},"BSB":{"text":"Surely extortion turns a wise man into a fool, and a bribe corrupts the heart."}},"definableWords":["man","fool","heart"],"peopleInVerse":[]},"8":{"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit.","ref":"Ecclesiastes 7:8","synthesized":"The end of a matter is better than the beginning, and a patient spirit is better than a proud one.","sources":{"KJV":{"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit."},"BSB":{"text":"The end of a matter is better than the beginning, and a patient spirit is better than a proud one."}},"definableWords":["beginning","spirit","one"],"peopleInVerse":[]},"9":{"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.","ref":"Ecclesiastes 7:9","synthesized":"Do not be quickly provoked in your spirit, for anger settles in the lap of a fool.","sources":{"KJV":{"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools."},"BSB":{"text":"Do not be quickly provoked in your spirit, for anger settles in the lap of a fool."}},"definableWords":["spirit","anger","fool"],"peopleInVerse":[]},"10":{"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this.","ref":"Ecclesiastes 7:10","synthesized":"Do not say, “Why were the old days better than these?” For it is unwise of you to ask about this.","sources":{"KJV":{"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this."},"BSB":{"text":"Do not say, “Why were the old days better than these?” For it is unwise of you to ask about this."}},"definableWords":["days"],"peopleInVerse":[]},"11":{"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun.","ref":"Ecclesiastes 7:11","synthesized":"Wisdom, like an inheritance, is good, and it benefits those who see the sun.","sources":{"KJV":{"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun."},"BSB":{"text":"Wisdom, like an inheritance, is good, and it benefits those who see the sun."}},"definableWords":["wisdom","good","see"],"peopleInVerse":[]},"12":{"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it.","ref":"Ecclesiastes 7:12","synthesized":"For wisdom, like money, is a shelter, and the advantage of knowledge is that wisdom preserves the life of its owner.","sources":{"KJV":{"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it."},"BSB":{"text":"For wisdom, like money, is a shelter, and the advantage of knowledge is that wisdom preserves the life of its owner."}},"definableWords":["wisdom","knowledge","life"],"peopleInVerse":[]},"13":{"text":"Consider the work of God: for who can make that straight, which he hath made crooked?","ref":"Ecclesiastes 7:13","synthesized":"Consider the work of God: Who can straighten what He has bent?","sources":{"KJV":{"text":"Consider the work of God: for who can make that straight, which he hath made crooked?"},"BSB":{"text":"Consider the work of God: Who can straighten what He has bent?"}},"definableWords":["work","God"],"peopleInVerse":[]},"14":{"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him.","ref":"Ecclesiastes 7:14","synthesized":"In the day of prosperity, be joyful, but in the day of adversity, consider this: God has made one of these along with the other, so that a man cannot discover anything that will come after him.","sources":{"KJV":{"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him."},"BSB":{"text":"In the day of prosperity, be joyful, but in the day of adversity, consider this: God has made one of these along with the other, so that a man cannot discover anything that will come after him."}},"definableWords":["day","God","made","one","man"],"peopleInVerse":[]},"15":{"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness.","ref":"Ecclesiastes 7:15","synthesized":"In my futile life I have seen both of these:  A righteous man perishing in his righteousness,   and a wicked man living long in his wickedness.","sources":{"KJV":{"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness."},"BSB":{"text":"In my futile life I have seen both of these:  A righteous man perishing in his righteousness,   and a wicked man living long in his wickedness."}},"definableWords":["life","righteous","man","righteousness","living"],"peopleInVerse":[]},"16":{"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself ?","ref":"Ecclesiastes 7:16","synthesized":"Do not be overly righteous, and do not make yourself too wise. Why should you destroy yourself?","sources":{"KJV":{"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself ?"},"BSB":{"text":"Do not be overly righteous, and do not make yourself too wise. Why should you destroy yourself?"}},"definableWords":["righteous","make"],"peopleInVerse":[]},"17":{"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?","ref":"Ecclesiastes 7:17","synthesized":"Do not be excessively wicked, and do not be a fool. Why should you die before your time?","sources":{"KJV":{"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?"},"BSB":{"text":"Do not be excessively wicked, and do not be a fool. Why should you die before your time?"}},"definableWords":["fool","die"],"peopleInVerse":[]},"18":{"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all.","ref":"Ecclesiastes 7:18","synthesized":"It is good to grasp the one and not let the other slip from your hand. For he who fears God will follow both warnings.","sources":{"KJV":{"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all."},"BSB":{"text":"It is good to grasp the one and not let the other slip from your hand. For he who fears God will follow both warnings."}},"definableWords":["good","one","God"],"peopleInVerse":[]},"19":{"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city.","ref":"Ecclesiastes 7:19","synthesized":"Wisdom makes the wise man stronger than ten rulers in a city.","sources":{"KJV":{"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city."},"BSB":{"text":"Wisdom makes the wise man stronger than ten rulers in a city."}},"definableWords":["wisdom","man"],"peopleInVerse":[]},"20":{"text":"For there is not a just man upon earth, that doeth good, and sinneth not.","ref":"Ecclesiastes 7:20","synthesized":"Surely there is no righteous man on earth who does good and never sins.","sources":{"KJV":{"text":"For there is not a just man upon earth, that doeth good, and sinneth not."},"BSB":{"text":"Surely there is no righteous man on earth who does good and never sins."}},"definableWords":["righteous","man","earth","good"],"peopleInVerse":[]},"21":{"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:","ref":"Ecclesiastes 7:21","synthesized":"Do not pay attention to every word that is spoken, or you may hear your servant cursing you.","sources":{"KJV":{"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:"},"BSB":{"text":"Do not pay attention to every word that is spoken, or you may hear your servant cursing you."}},"definableWords":["word","or","hear","servant"],"peopleInVerse":[]},"22":{"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others.","ref":"Ecclesiastes 7:22","synthesized":"For you know in your heart that many times you yourself have cursed others.","sources":{"KJV":{"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others."},"BSB":{"text":"For you know in your heart that many times you yourself have cursed others."}},"definableWords":["heart","cursed"],"peopleInVerse":[]},"23":{"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me.","ref":"Ecclesiastes 7:23","synthesized":"All this I tested by wisdom, saying, “I resolve to be wise.” But it was beyond me.","sources":{"KJV":{"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me."},"BSB":{"text":"All this I tested by wisdom, saying, “I resolve to be wise.” But it was beyond me."}},"definableWords":["wisdom"],"peopleInVerse":[]},"24":{"text":"That which is far off, and exceeding deep, who can find it out?","ref":"Ecclesiastes 7:24","synthesized":"What exists is out of reach and very deep. Who can fathom it?","sources":{"KJV":{"text":"That which is far off, and exceeding deep, who can find it out?"},"BSB":{"text":"What exists is out of reach and very deep. Who can fathom it?"}},"definableWords":["deep"],"peopleInVerse":[]},"25":{"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:","ref":"Ecclesiastes 7:25","synthesized":"I directed my mind to understand, to explore, to search out wisdom and explanations, and to understand the stupidity of wickedness and the folly of madness.","sources":{"KJV":{"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:"},"BSB":{"text":"I directed my mind to understand, to explore, to search out wisdom and explanations, and to understand the stupidity of wickedness and the folly of madness."}},"definableWords":["mind","wisdom"],"peopleInVerse":[]},"26":{"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her.","ref":"Ecclesiastes 7:26","synthesized":"And I find more bitter than death the woman who is a snare, whose heart is a net, and whose hands are chains. The man who pleases God escapes her, but the sinner is ensnared.","sources":{"KJV":{"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her."},"BSB":{"text":"And I find more bitter than death the woman who is a snare, whose heart is a net, and whose hands are chains. The man who pleases God escapes her, but the sinner is ensnared."}},"definableWords":["death","woman","heart","man","God"],"peopleInVerse":[]},"27":{"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:","ref":"Ecclesiastes 7:27","synthesized":"“Behold,” says the Teacher, “I have discovered this by adding one thing to another to find an explanation.","sources":{"KJV":{"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:"},"BSB":{"text":"“Behold,” says the Teacher, “I have discovered this by adding one thing to another to find an explanation."}},"definableWords":["one"],"peopleInVerse":[]},"28":{"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found.","ref":"Ecclesiastes 7:28","synthesized":"While my soul was still searching but not finding, among a thousand I have found one upright man, but among all these I have not found one such woman.","sources":{"KJV":{"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found."},"BSB":{"text":"While my soul was still searching but not finding, among a thousand I have found one upright man, but among all these I have not found one such woman."}},"definableWords":["soul","one","man","woman"],"peopleInVerse":[]},"29":{"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions.","ref":"Ecclesiastes 7:29","synthesized":"Only this have I found: I have discovered that God made men upright, but they have sought out many schemes.”","sources":{"KJV":{"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions."},"BSB":{"text":"Only this have I found: I have discovered that God made men upright, but they have sought out many schemes.”"}},"definableWords":["God","made","men"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"WHO IS AS THE WISE MAN?","verses":{"1":{"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed.","ref":"Ecclesiastes 8:1","synthesized":"Who is like the wise man? Who knows the interpretation of a matter? A man’s wisdom brightens his face, and the sternness of his face is changed.","sources":{"KJV":{"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed."},"BSB":{"text":"Who is like the wise man? Who knows the interpretation of a matter? A man’s wisdom brightens his face, and the sternness of his face is changed."}},"definableWords":["man","wisdom"],"peopleInVerse":[]},"2":{"text":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God.","ref":"Ecclesiastes 8:2","synthesized":"Keep the king’s command, I say, because of your oath before God.","sources":{"KJV":{"text":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God."},"BSB":{"text":"Keep the king’s command, I say, because of your oath before God."}},"definableWords":["keep","king","God"],"peopleInVerse":[]},"3":{"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him.","ref":"Ecclesiastes 8:3","synthesized":"Do not hasten to leave his presence, and do not persist in a bad cause, for he will do whatever he pleases.","sources":{"KJV":{"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him."},"BSB":{"text":"Do not hasten to leave his presence, and do not persist in a bad cause, for he will do whatever he pleases."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?","ref":"Ecclesiastes 8:4","synthesized":"For the king’s word is supreme, and who can say to him, “What are you doing?”","sources":{"KJV":{"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?"},"BSB":{"text":"For the king’s word is supreme, and who can say to him, “What are you doing?”"}},"definableWords":["king","word"],"peopleInVerse":[]},"5":{"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment.","ref":"Ecclesiastes 8:5","synthesized":"Whoever keeps his command will come to no harm, and a wise heart knows the right time and procedure.","sources":{"KJV":{"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment."},"BSB":{"text":"Whoever keeps his command will come to no harm, and a wise heart knows the right time and procedure."}},"definableWords":["heart"],"peopleInVerse":[]},"6":{"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him.","ref":"Ecclesiastes 8:6","synthesized":"For there is a right time and procedure to every purpose, though a man’s misery weighs heavily upon him.","sources":{"KJV":{"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him."},"BSB":{"text":"For there is a right time and procedure to every purpose, though a man’s misery weighs heavily upon him."}},"definableWords":["man"],"peopleInVerse":[]},"7":{"text":"For he knoweth not that which shall be: for who can tell him when it shall be?","ref":"Ecclesiastes 8:7","synthesized":"Since no one knows what will happen, who can tell him what is to come?","sources":{"KJV":{"text":"For he knoweth not that which shall be: for who can tell him when it shall be?"},"BSB":{"text":"Since no one knows what will happen, who can tell him what is to come?"}},"definableWords":["one"],"peopleInVerse":[]},"8":{"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it.","ref":"Ecclesiastes 8:8","synthesized":"As no man has power over the wind to contain it, so no one has authority over his day of death. As no one can be discharged in wartime, so wickedness will not release those who practice it.","sources":{"KJV":{"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it."},"BSB":{"text":"As no man has power over the wind to contain it, so no one has authority over his day of death. As no one can be discharged in wartime, so wickedness will not release those who practice it."}},"definableWords":["man","one","day","death"],"peopleInVerse":[]},"9":{"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt.","ref":"Ecclesiastes 8:9","synthesized":"All this I have seen, applying my mind to every deed that is done under the sun; there is a time when one man lords it over another to his own detriment.","sources":{"KJV":{"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt."},"BSB":{"text":"All this I have seen, applying my mind to every deed that is done under the sun; there is a time when one man lords it over another to his own detriment."}},"definableWords":["mind","one","man"],"peopleInVerse":[]},"10":{"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity.","ref":"Ecclesiastes 8:10","synthesized":"Then too, I saw the burial of the wicked who used to go in and out of the holy place, and they were praised in the city where they had done so. This too is futile.","sources":{"KJV":{"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity."},"BSB":{"text":"Then too, I saw the burial of the wicked who used to go in and out of the holy place, and they were praised in the city where they had done so. This too is futile."}},"definableWords":["saw","holy"],"peopleInVerse":[]},"11":{"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.","ref":"Ecclesiastes 8:11","synthesized":"When the sentence for a crime is not speedily executed, the hearts of men become fully set on doing evil.","sources":{"KJV":{"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil."},"BSB":{"text":"When the sentence for a crime is not speedily executed, the hearts of men become fully set on doing evil."}},"definableWords":["men","evil"],"peopleInVerse":[]},"12":{"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:","ref":"Ecclesiastes 8:12","synthesized":"Although a sinner does evil a hundred times and still lives long, yet I also know that it will go well with those who fear God, who are reverent in His presence.","sources":{"KJV":{"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:"},"BSB":{"text":"Although a sinner does evil a hundred times and still lives long, yet I also know that it will go well with those who fear God, who are reverent in His presence."}},"definableWords":["evil","fear","God"],"peopleInVerse":[]},"13":{"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God.","ref":"Ecclesiastes 8:13","synthesized":"Yet because the wicked do not fear God, it will not go well with them, and their days will not lengthen like a shadow.","sources":{"KJV":{"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God."},"BSB":{"text":"Yet because the wicked do not fear God, it will not go well with them, and their days will not lengthen like a shadow."}},"definableWords":["fear","God","days"],"peopleInVerse":[]},"14":{"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity.","ref":"Ecclesiastes 8:14","synthesized":"There is a futility that is done on the earth: There are righteous men who get what the actions of the wicked deserve, and there are wicked men who get what the actions of the righteous deserve. I say that this too is futile.","sources":{"KJV":{"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity."},"BSB":{"text":"There is a futility that is done on the earth: There are righteous men who get what the actions of the wicked deserve, and there are wicked men who get what the actions of the righteous deserve. I say that this too is futile."}},"definableWords":["earth","righteous","men"],"peopleInVerse":[]},"15":{"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun.","ref":"Ecclesiastes 8:15","synthesized":"So I commended the enjoyment of life, because there is nothing better for a man under the sun than to eat and drink and be merry. For this joy will accompany him in his labor during the days of his life that God gives him under the sun.","sources":{"KJV":{"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun."},"BSB":{"text":"So I commended the enjoyment of life, because there is nothing better for a man under the sun than to eat and drink and be merry. For this joy will accompany him in his labor during the days of his life that God gives him under the sun."}},"definableWords":["life","man","joy","days","God"],"peopleInVerse":[]},"16":{"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)","ref":"Ecclesiastes 8:16","synthesized":"When I applied my mind to know wisdom and to observe the task that one performs on the earth—though his eyes do not see sleep in the day or even in the night—","sources":{"KJV":{"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)"},"BSB":{"text":"When I applied my mind to know wisdom and to observe the task that one performs on the earth—though his eyes do not see sleep in the day or even in the night—"}},"definableWords":["mind","wisdom","one","earth","see","day","or","night"],"peopleInVerse":[]},"17":{"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea farther; though a wise man think to know it, yet shall he not be able to find it.","ref":"Ecclesiastes 8:17","synthesized":"I saw every work of God, and that a man is unable to comprehend the work that is done under the sun. Despite his efforts to search it out, he cannot find its meaning; even if the wise man claims to know, he is unable to comprehend.","sources":{"KJV":{"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea farther; though a wise man think to know it, yet shall he not be able to find it."},"BSB":{"text":"I saw every work of God, and that a man is unable to comprehend the work that is done under the sun. Despite his efforts to search it out, he cannot find its meaning; even if the wise man claims to know, he is unable to comprehend."}},"definableWords":["saw","work","God","man"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"WHATSOEVER THY HAND FINDETH TO DO","verses":{"1":{"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them.","ref":"Ecclesiastes 9:1","synthesized":"So I took all this to heart and concluded that the righteous and the wise, as well as their deeds, are in God’s hands. Man does not know what lies ahead, whether love or hate.","sources":{"KJV":{"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them."},"BSB":{"text":"So I took all this to heart and concluded that the righteous and the wise, as well as their deeds, are in God’s hands. Man does not know what lies ahead, whether love or hate."}},"definableWords":["heart","righteous","God","man","love","or"],"peopleInVerse":[]},"2":{"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath.","ref":"Ecclesiastes 9:2","synthesized":"It is the same for all: There is a common fate for the righteous and the wicked, for the good and the bad, for the clean and the unclean, for the one who sacrifices and the one who does not. As it is for the good, so it is for the sinner; as it is for the one who makes a vow, so it is for the one who refuses to take a vow.","sources":{"KJV":{"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath."},"BSB":{"text":"It is the same for all: There is a common fate for the righteous and the wicked, for the good and the bad, for the clean and the unclean, for the one who sacrifices and the one who does not. As it is for the good, so it is for the sinner; as it is for the one who makes a vow, so it is for the one who refuses to take a vow."}},"definableWords":["righteous","good","one"],"peopleInVerse":[]},"3":{"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.","ref":"Ecclesiastes 9:3","synthesized":"This is an evil in everything that is done under the sun: There is one fate for everyone. Furthermore, the hearts of men are full of evil and madness while they are alive, and afterward they join the dead.","sources":{"KJV":{"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead."},"BSB":{"text":"This is an evil in everything that is done under the sun: There is one fate for everyone. Furthermore, the hearts of men are full of evil and madness while they are alive, and afterward they join the dead."}},"definableWords":["evil","one","men"],"peopleInVerse":[]},"4":{"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion.","ref":"Ecclesiastes 9:4","synthesized":"There is hope, however, for anyone who is among the living; for even a live dog is better than a dead lion.","sources":{"KJV":{"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion."},"BSB":{"text":"There is hope, however, for anyone who is among the living; for even a live dog is better than a dead lion."}},"definableWords":["hope","living","live","lion"],"peopleInVerse":[]},"5":{"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten.","ref":"Ecclesiastes 9:5","synthesized":"For the living know that they will die, but the dead know nothing. They have no further reward, because the memory of them is forgotten.","sources":{"KJV":{"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten."},"BSB":{"text":"For the living know that they will die, but the dead know nothing. They have no further reward, because the memory of them is forgotten."}},"definableWords":["living","die"],"peopleInVerse":[]},"6":{"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun.","ref":"Ecclesiastes 9:6","synthesized":"Their love, their hate, and their envy have already vanished, and they will never again have a share in all that is done under the sun.","sources":{"KJV":{"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun."},"BSB":{"text":"Their love, their hate, and their envy have already vanished, and they will never again have a share in all that is done under the sun."}},"definableWords":["love"],"peopleInVerse":[]},"7":{"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works.","ref":"Ecclesiastes 9:7","synthesized":"Go, eat your bread with joy, and drink your wine with a cheerful heart, for God has already approved your works:","sources":{"KJV":{"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works."},"BSB":{"text":"Go, eat your bread with joy, and drink your wine with a cheerful heart, for God has already approved your works:"}},"definableWords":["joy","heart","God","works"],"peopleInVerse":[]},"8":{"text":"Let thy garments be always white; and let thy head lack no ointment.","ref":"Ecclesiastes 9:8","synthesized":"Let your garments always be white, and never spare the oil for your head.","sources":{"KJV":{"text":"Let thy garments be always white; and let thy head lack no ointment."},"BSB":{"text":"Let your garments always be white, and never spare the oil for your head."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun.","ref":"Ecclesiastes 9:9","synthesized":"Enjoy life with your beloved wife all the days of the fleeting life that God has given you under the sun—all your fleeting days. For this is your portion in life and in your labor under the sun.","sources":{"KJV":{"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun."},"BSB":{"text":"Enjoy life with your beloved wife all the days of the fleeting life that God has given you under the sun—all your fleeting days. For this is your portion in life and in your labor under the sun."}},"definableWords":["life","wife","days","God"],"peopleInVerse":[]},"10":{"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest.","ref":"Ecclesiastes 9:10","synthesized":"Whatever you find to do with your hands, do it with all your might, for in Sheol, where you are going, there is no work or planning or knowledge or wisdom.","sources":{"KJV":{"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest."},"BSB":{"text":"Whatever you find to do with your hands, do it with all your might, for in Sheol, where you are going, there is no work or planning or knowledge or wisdom."}},"definableWords":["work","or","knowledge","wisdom"],"peopleInVerse":[]},"11":{"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all.","ref":"Ecclesiastes 9:11","synthesized":"I saw something else under the sun: The race is not to the swift, nor the battle to the strong; neither is the bread to the wise, nor the wealth to the intelligent, nor the favor to the skillful. For time and chance happen to all.","sources":{"KJV":{"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all."},"BSB":{"text":"I saw something else under the sun: The race is not to the swift, nor the battle to the strong; neither is the bread to the wise, nor the wealth to the intelligent, nor the favor to the skillful. For time and chance happen to all."}},"definableWords":["saw","strong"],"peopleInVerse":[]},"12":{"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them.","ref":"Ecclesiastes 9:12","synthesized":"For surely no man knows his time: Like fish caught in a cruel net or birds trapped in a snare, so men are ensnared in an evil time that suddenly falls upon them.","sources":{"KJV":{"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them."},"BSB":{"text":"For surely no man knows his time: Like fish caught in a cruel net or birds trapped in a snare, so men are ensnared in an evil time that suddenly falls upon them."}},"definableWords":["man","fish","or","birds","men","evil"],"peopleInVerse":[]},"13":{"text":"This wisdom have I seen also under the sun, and it seemed great unto me:","ref":"Ecclesiastes 9:13","synthesized":"I have also seen this wisdom under the sun, and it was great to me:","sources":{"KJV":{"text":"This wisdom have I seen also under the sun, and it seemed great unto me:"},"BSB":{"text":"I have also seen this wisdom under the sun, and it was great to me:"}},"definableWords":["wisdom","great"],"peopleInVerse":[]},"14":{"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:","ref":"Ecclesiastes 9:14","synthesized":"There was a small city with few men. A mighty king came against it, surrounded it, and built large siege ramps against it.","sources":{"KJV":{"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:"},"BSB":{"text":"There was a small city with few men. A mighty king came against it, surrounded it, and built large siege ramps against it."}},"definableWords":["men","mighty","king"],"peopleInVerse":[]},"15":{"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man.","ref":"Ecclesiastes 9:15","synthesized":"Now a poor wise man was found in the city, and he saved the city by his wisdom. Yet no one remembered that poor man.","sources":{"KJV":{"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man."},"BSB":{"text":"Now a poor wise man was found in the city, and he saved the city by his wisdom. Yet no one remembered that poor man."}},"definableWords":["man","wisdom","one","remembered"],"peopleInVerse":[]},"16":{"text":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard.","ref":"Ecclesiastes 9:16","synthesized":"And I said, “Wisdom is better than strength, but the wisdom of the poor man is despised, and his words are not heeded.”","sources":{"KJV":{"text":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard."},"BSB":{"text":"And I said, “Wisdom is better than strength, but the wisdom of the poor man is despised, and his words are not heeded.”"}},"definableWords":["wisdom","man"],"peopleInVerse":[]},"17":{"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools.","ref":"Ecclesiastes 9:17","synthesized":"The calm words of the wise are heeded over the shouts of a ruler among fools.","sources":{"KJV":{"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools."},"BSB":{"text":"The calm words of the wise are heeded over the shouts of a ruler among fools."}},"definableWords":["ruler"],"peopleInVerse":[]},"18":{"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good.","ref":"Ecclesiastes 9:18","synthesized":"Wisdom is better than weapons of war, but one sinner destroys much good.","sources":{"KJV":{"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good."},"BSB":{"text":"Wisdom is better than weapons of war, but one sinner destroys much good."}},"definableWords":["wisdom","one","good"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"DEAD FLIES — A LITTLE FOLLY","verses":{"1":{"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour.","ref":"Ecclesiastes 10:1","synthesized":"As dead flies bring a stench to the perfumer’s oil, so a little folly outweighs wisdom and honor.","sources":{"KJV":{"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour."},"BSB":{"text":"As dead flies bring a stench to the perfumer’s oil, so a little folly outweighs wisdom and honor."}},"definableWords":["wisdom"],"peopleInVerse":[]},"2":{"text":"A wise man’s heart is at his right hand; but a fool’s heart at his left.","ref":"Ecclesiastes 10:2","synthesized":"A wise man’s heart inclines to the right, but the heart of a fool to the left.","sources":{"KJV":{"text":"A wise man’s heart is at his right hand; but a fool’s heart at his left."},"BSB":{"text":"A wise man’s heart inclines to the right, but the heart of a fool to the left."}},"definableWords":["man","heart","fool"],"peopleInVerse":[]},"3":{"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool.","ref":"Ecclesiastes 10:3","synthesized":"Even as the fool walks along the road, his sense is lacking, and he shows everyone that he is a fool.","sources":{"KJV":{"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool."},"BSB":{"text":"Even as the fool walks along the road, his sense is lacking, and he shows everyone that he is a fool."}},"definableWords":["fool"],"peopleInVerse":[]},"4":{"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences.","ref":"Ecclesiastes 10:4","synthesized":"If the ruler’s temper flares against you, do not abandon your post, for calmness lays great offenses to rest.","sources":{"KJV":{"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences."},"BSB":{"text":"If the ruler’s temper flares against you, do not abandon your post, for calmness lays great offenses to rest."}},"definableWords":["ruler","great","rest"],"peopleInVerse":[]},"5":{"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:","ref":"Ecclesiastes 10:5","synthesized":"There is an evil I have seen under the sun— an error that proceeds from the ruler:","sources":{"KJV":{"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:"},"BSB":{"text":"There is an evil I have seen under the sun— an error that proceeds from the ruler:"}},"definableWords":["evil","ruler"],"peopleInVerse":[]},"6":{"text":"Folly is set in great dignity, and the rich sit in low place.","ref":"Ecclesiastes 10:6","synthesized":"Folly is appointed to great heights, but the rich sit in lowly positions.","sources":{"KJV":{"text":"Folly is set in great dignity, and the rich sit in low place."},"BSB":{"text":"Folly is appointed to great heights, but the rich sit in lowly positions."}},"definableWords":["great"],"peopleInVerse":[]},"7":{"text":"I have seen servants upon horses, and princes walking as servants upon the earth.","ref":"Ecclesiastes 10:7","synthesized":"I have seen slaves on horseback, while princes go on foot like slaves.","sources":{"KJV":{"text":"I have seen servants upon horses, and princes walking as servants upon the earth."},"BSB":{"text":"I have seen slaves on horseback, while princes go on foot like slaves."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him.","ref":"Ecclesiastes 10:8","synthesized":"He who digs a pit may fall into it, and he who breaches a wall may be bitten by a snake.","sources":{"KJV":{"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him."},"BSB":{"text":"He who digs a pit may fall into it, and he who breaches a wall may be bitten by a snake."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby.","ref":"Ecclesiastes 10:9","synthesized":"The one who quarries stones may be injured by them, and he who splits logs endangers himself.","sources":{"KJV":{"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby."},"BSB":{"text":"The one who quarries stones may be injured by them, and he who splits logs endangers himself."}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct.","ref":"Ecclesiastes 10:10","synthesized":"If the axe is dull and the blade unsharpened, more strength must be exerted, but skill produces success.","sources":{"KJV":{"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct."},"BSB":{"text":"If the axe is dull and the blade unsharpened, more strength must be exerted, but skill produces success."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Surely the serpent will bite without enchantment; and a babbler is no better.","ref":"Ecclesiastes 10:11","synthesized":"If the snake bites before it is charmed, there is no profit for the charmer.","sources":{"KJV":{"text":"Surely the serpent will bite without enchantment; and a babbler is no better."},"BSB":{"text":"If the snake bites before it is charmed, there is no profit for the charmer."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself.","ref":"Ecclesiastes 10:12","synthesized":"The words of a wise man’s mouth are gracious, but the lips of a fool consume him.","sources":{"KJV":{"text":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself."},"BSB":{"text":"The words of a wise man’s mouth are gracious, but the lips of a fool consume him."}},"definableWords":["man","fool"],"peopleInVerse":[]},"13":{"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness.","ref":"Ecclesiastes 10:13","synthesized":"The beginning of his talk is folly, and the end of his speech is evil madness.","sources":{"KJV":{"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness."},"BSB":{"text":"The beginning of his talk is folly, and the end of his speech is evil madness."}},"definableWords":["beginning","evil"],"peopleInVerse":[]},"14":{"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?","ref":"Ecclesiastes 10:14","synthesized":"Yet the fool multiplies words. No one knows what is coming, and who can tell him what will come after him?","sources":{"KJV":{"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?"},"BSB":{"text":"Yet the fool multiplies words. No one knows what is coming, and who can tell him what will come after him?"}},"definableWords":["fool","one"],"peopleInVerse":[]},"15":{"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city.","ref":"Ecclesiastes 10:15","synthesized":"The toil of a fool wearies him, for he does not know the way to the city.","sources":{"KJV":{"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city."},"BSB":{"text":"The toil of a fool wearies him, for he does not know the way to the city."}},"definableWords":["fool","way"],"peopleInVerse":[]},"16":{"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!","ref":"Ecclesiastes 10:16","synthesized":"Woe to you, O land whose king is a youth, and whose princes feast in the morning.","sources":{"KJV":{"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!"},"BSB":{"text":"Woe to you, O land whose king is a youth, and whose princes feast in the morning."}},"definableWords":["land","king"],"peopleInVerse":[]},"17":{"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!","ref":"Ecclesiastes 10:17","synthesized":"Blessed are you, O land whose king is a son of nobles, and whose princes feast at the proper time— for strength and not for drunkenness.","sources":{"KJV":{"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!"},"BSB":{"text":"Blessed are you, O land whose king is a son of nobles, and whose princes feast at the proper time— for strength and not for drunkenness."}},"definableWords":["blessed","land","king","son"],"peopleInVerse":[]},"18":{"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through.","ref":"Ecclesiastes 10:18","synthesized":"Through laziness the roof caves in, and in the hands of the idle, the house leaks.","sources":{"KJV":{"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through."},"BSB":{"text":"Through laziness the roof caves in, and in the hands of the idle, the house leaks."}},"definableWords":["house"],"peopleInVerse":[]},"19":{"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things.","ref":"Ecclesiastes 10:19","synthesized":"A feast is prepared for laughter, and wine makes life merry, but money is the answer for everything.","sources":{"KJV":{"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things."},"BSB":{"text":"A feast is prepared for laughter, and wine makes life merry, but money is the answer for everything."}},"definableWords":["life"],"peopleInVerse":[]},"20":{"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter.","ref":"Ecclesiastes 10:20","synthesized":"Do not curse the king even in your thoughts, or curse the rich even in your bedroom, for a bird of the air may carry your words, and a winged creature may report your speech.","sources":{"KJV":{"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter."},"BSB":{"text":"Do not curse the king even in your thoughts, or curse the rich even in your bedroom, for a bird of the air may carry your words, and a winged creature may report your speech."}},"definableWords":["curse","king","or","bird"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"CAST THY BREAD UPON THE WATERS","verses":{"1":{"text":"Cast thy bread upon the waters: for thou shalt find it after many days.","ref":"Ecclesiastes 11:1","synthesized":"Cast your bread upon the waters, for after many days you will find it again.","sources":{"KJV":{"text":"Cast thy bread upon the waters: for thou shalt find it after many days."},"BSB":{"text":"Cast your bread upon the waters, for after many days you will find it again."}},"definableWords":["waters","days"],"peopleInVerse":[]},"2":{"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth.","ref":"Ecclesiastes 11:2","synthesized":"Divide your portion among seven, or even eight, for you do not know what disaster may befall the land.","sources":{"KJV":{"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth."},"BSB":{"text":"Divide your portion among seven, or even eight, for you do not know what disaster may befall the land."}},"definableWords":["or","land"],"peopleInVerse":[]},"3":{"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be.","ref":"Ecclesiastes 11:3","synthesized":"If the clouds are full, they will pour out rain upon the earth; whether a tree falls to the south or to the north, in the place where it falls, there it will lie.","sources":{"KJV":{"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be."},"BSB":{"text":"If the clouds are full, they will pour out rain upon the earth; whether a tree falls to the south or to the north, in the place where it falls, there it will lie."}},"definableWords":["earth","tree","or"],"peopleInVerse":[]},"4":{"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap.","ref":"Ecclesiastes 11:4","synthesized":"He who watches the wind will fail to sow, and he who observes the clouds will fail to reap.","sources":{"KJV":{"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap."},"BSB":{"text":"He who watches the wind will fail to sow, and he who observes the clouds will fail to reap."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all.","ref":"Ecclesiastes 11:5","synthesized":"As you do not know the path of the wind, or how the bones are formed in a mother’s womb, so you cannot understand the work of God, the Maker of all things.","sources":{"KJV":{"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all."},"BSB":{"text":"As you do not know the path of the wind, or how the bones are formed in a mother’s womb, so you cannot understand the work of God, the Maker of all things."}},"definableWords":["or","bones","formed","mother","work","God"],"peopleInVerse":[]},"6":{"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good.","ref":"Ecclesiastes 11:6","synthesized":"Sow your seed in the morning, and do not rest your hands in the evening, for you do not know which will succeed, whether this or that, or if both will equally prosper.","sources":{"KJV":{"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good."},"BSB":{"text":"Sow your seed in the morning, and do not rest your hands in the evening, for you do not know which will succeed, whether this or that, or if both will equally prosper."}},"definableWords":["seed","rest","or"],"peopleInVerse":[]},"7":{"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:","ref":"Ecclesiastes 11:7","synthesized":"Light is sweet, and it pleases the eyes to see the sun.","sources":{"KJV":{"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:"},"BSB":{"text":"Light is sweet, and it pleases the eyes to see the sun."}},"definableWords":["light","see"],"peopleInVerse":[]},"8":{"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity.","ref":"Ecclesiastes 11:8","synthesized":"So if a man lives many years, let him rejoice in them all. But let him remember the days of darkness, for they will be many. Everything to come is futile.","sources":{"KJV":{"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity."},"BSB":{"text":"So if a man lives many years, let him rejoice in them all. But let him remember the days of darkness, for they will be many. Everything to come is futile."}},"definableWords":["man","years","remember","days","darkness"],"peopleInVerse":[]},"9":{"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment.","ref":"Ecclesiastes 11:9","synthesized":"Rejoice, O young man, while you are young, and let your heart be glad in the days of your youth. Walk in the ways of your heart and in the sight of your eyes, but know that for all these things God will bring you to judgment.","sources":{"KJV":{"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment."},"BSB":{"text":"Rejoice, O young man, while you are young, and let your heart be glad in the days of your youth. Walk in the ways of your heart and in the sight of your eyes, but know that for all these things God will bring you to judgment."}},"definableWords":["man","heart","days","walk","God","judgment"],"peopleInVerse":[]},"10":{"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity.","ref":"Ecclesiastes 11:10","synthesized":"So banish sorrow from your heart, and cast off pain from your body, for youth and vigor are fleeting.","sources":{"KJV":{"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity."},"BSB":{"text":"So banish sorrow from your heart, and cast off pain from your body, for youth and vigor are fleeting."}},"definableWords":["heart"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"REMEMBER THY CREATOR","verses":{"1":{"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;","ref":"Ecclesiastes 12:1","synthesized":"Remember your Creator in the days of your youth, before the days of adversity come and the years approach of which you will say, “I find no pleasure in them,”","sources":{"KJV":{"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;"},"BSB":{"text":"Remember your Creator in the days of your youth, before the days of adversity come and the years approach of which you will say, “I find no pleasure in them,”"}},"definableWords":["remember","days","years"],"peopleInVerse":[]},"2":{"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:","ref":"Ecclesiastes 12:2","synthesized":"before the light of the sun, moon, and stars is darkened, and the clouds return after the rain,","sources":{"KJV":{"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:"},"BSB":{"text":"before the light of the sun, moon, and stars is darkened, and the clouds return after the rain,"}},"definableWords":["light"],"peopleInVerse":[]},"3":{"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,","ref":"Ecclesiastes 12:3","synthesized":"on the day the keepers of the house tremble and the strong men stoop, when those grinding cease because they are few and those watching through windows see dimly,","sources":{"KJV":{"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,"},"BSB":{"text":"on the day the keepers of the house tremble and the strong men stoop, when those grinding cease because they are few and those watching through windows see dimly,"}},"definableWords":["day","house","strong","men","see"],"peopleInVerse":[]},"4":{"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;","ref":"Ecclesiastes 12:4","synthesized":"when the doors to the street are shut and the sound of the mill fades away, when one rises at the sound of a bird and all the daughters of song grow faint,","sources":{"KJV":{"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;"},"BSB":{"text":"when the doors to the street are shut and the sound of the mill fades away, when one rises at the sound of a bird and all the daughters of song grow faint,"}},"definableWords":["one","bird","daughters"],"peopleInVerse":[]},"5":{"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:","ref":"Ecclesiastes 12:5","synthesized":"when men fear the heights and dangers of the road, when the almond tree blossoms, the grasshopper loses its spring, and the caper berry shrivels— for then man goes to his eternal home and mourners walk the streets.","sources":{"KJV":{"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:"},"BSB":{"text":"when men fear the heights and dangers of the road, when the almond tree blossoms, the grasshopper loses its spring, and the caper berry shrivels— for then man goes to his eternal home and mourners walk the streets."}},"definableWords":["men","fear","tree","man","eternal","walk"],"peopleInVerse":[]},"6":{"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern.","ref":"Ecclesiastes 12:6","synthesized":"Remember Him before the silver cord is snapped and the golden bowl is crushed, before the pitcher is shattered at the spring and the wheel is broken at the well,","sources":{"KJV":{"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern."},"BSB":{"text":"Remember Him before the silver cord is snapped and the golden bowl is crushed, before the pitcher is shattered at the spring and the wheel is broken at the well,"}},"definableWords":["remember"],"peopleInVerse":[]},"7":{"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it.","ref":"Ecclesiastes 12:7","synthesized":"before the dust returns to the ground from which it came and the spirit returns to God who gave it.","sources":{"KJV":{"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it."},"BSB":{"text":"before the dust returns to the ground from which it came and the spirit returns to God who gave it."}},"definableWords":["ground","spirit","God"],"peopleInVerse":[]},"8":{"text":"Vanity of vanities, saith the preacher; all is vanity.","ref":"Ecclesiastes 12:8","synthesized":"“Futility of futilities,” says the Teacher. “Everything is futile!”","sources":{"KJV":{"text":"Vanity of vanities, saith the preacher; all is vanity."},"BSB":{"text":"“Futility of futilities,” says the Teacher. “Everything is futile!”"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs.","ref":"Ecclesiastes 12:9","synthesized":"Not only was the Teacher wise, but he also taught the people knowledge; he pondered, searched out, and arranged many proverbs.","sources":{"KJV":{"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs."},"BSB":{"text":"Not only was the Teacher wise, but he also taught the people knowledge; he pondered, searched out, and arranged many proverbs."}},"definableWords":["people","knowledge"],"peopleInVerse":[]},"10":{"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth.","ref":"Ecclesiastes 12:10","synthesized":"The Teacher searched to find delightful sayings and to record accurate words of truth.","sources":{"KJV":{"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth."},"BSB":{"text":"The Teacher searched to find delightful sayings and to record accurate words of truth."}},"definableWords":["truth"],"peopleInVerse":[]},"11":{"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd.","ref":"Ecclesiastes 12:11","synthesized":"The words of the wise are like goads, and the anthologies of the masters are like firmly embedded nails driven by a single Shepherd.","sources":{"KJV":{"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd."},"BSB":{"text":"The words of the wise are like goads, and the anthologies of the masters are like firmly embedded nails driven by a single Shepherd."}},"definableWords":["shepherd"],"peopleInVerse":[]},"12":{"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.","ref":"Ecclesiastes 12:12","synthesized":"And by these, my son, be further warned: There is no end to the making of many books, and much study wearies the body.","sources":{"KJV":{"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh."},"BSB":{"text":"And by these, my son, be further warned: There is no end to the making of many books, and much study wearies the body."}},"definableWords":["son"],"peopleInVerse":[]},"13":{"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man.","ref":"Ecclesiastes 12:13","synthesized":"When all has been heard, the conclusion of the matter is this: Fear God and keep His commandments, because this is the whole duty of man.","sources":{"KJV":{"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man."},"BSB":{"text":"When all has been heard, the conclusion of the matter is this: Fear God and keep His commandments, because this is the whole duty of man."}},"definableWords":["fear","God","keep","man"],"peopleInVerse":[]},"14":{"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.","ref":"Ecclesiastes 12:14","synthesized":"For God will bring every deed into judgment, along with every hidden thing, whether good or evil.","sources":{"KJV":{"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil."},"BSB":{"text":"For God will bring every deed into judgment, along with every hidden thing, whether good or evil."}},"definableWords":["God","judgment","good","or","evil"],"peopleInVerse":[]}}}};